import requests, json
r = requests.post('https://text.pollinations.ai/', json={'messages': [{'role': 'user', 'content': 'Act as a clinical pharmacologist. The user has provided the following medications: "naxdom250".\nREAL-TIME WEB SEARCH CONTEXT: "Naxdom 250 is a combination medicine used to treat migraine..."\nUse this context to identify the drug if you dont recognize the brand name.\nProvide a highly detailed drug interaction and safety report. If you encounter an unrecognized or regional brand name (e.g. Naxdom), DO NOT say it is unknown. Instead, intelligently infer its active generic ingredients (e.g. Naproxen + Domperidone) and base your report entirely on those generic ingredients.\nRespond STRICTLY with a JSON array of objects. Each object must have these exact keys:\n- "severity" (string: Major, Moderate, Minor, or Info)\n- "title" (string: short title of interaction or finding)\n- "description" (string: detailed explanation)\n- "points" (array of strings: actionable bullet points)'}], 'model': 'openai', 'jsonMode': True})
with open('test_api_4.txt', 'w', encoding='utf-8') as f:
    f.write(r.text)
